import openpyxl
wb = openpyxl.load_workbook('input.xlsx')
print('Sheets:', wb.sheetnames)
ws = wb.active
print(f'Active sheet: {ws.title}')
print(f'Max row: {ws.max_row}, Max col: {ws.max_column}')
print()
# Print header row
for row in ws.iter_rows(min_row=1, max_row=1, max_col=ws.max_column, values_only=False):
    for c in row:
        if c.value is not None:
            print(f'{c.column_letter}1 = {c.value}')
print()
# Print first few data rows
for r in range(2, min(ws.max_row+1, 20)):
    vals = []
    for c in ws[r]:
        if c.value is not None:
            vals.append(f'{c.column_letter}{r}={c.value}')
    if vals:
        print(vals)
"
